Context:
ConfirmationDialog.tsx lines 72-79:
```tsx
{current.params && Object.keys(current.params).length > 0 && (
  <details className="mt-2">
    <summary className="cursor-pointer text-xs">Parameters</summary>
    <pre className="mt-1 max-h-40 overflow-auto rounded border border-border bg-card px-2 py-1 font-mono text-xs leading-tight">
      {JSON.stringify(current.params, null, 2)}
    </pre>
  </details>
)}
```

The params display only appears when `Object.keys(current.params).length > 0`.

For a tool WITH params, use `browser_open_tab` which requires `{ url: string }`. Set it to 'ask' permission.
For a tool WITHOUT params, use `browser_list_tabs` which has no required params.

```typescript
test('dialog shows expandable parameters for tools with params', async ({
  mcpServer, extensionContext, mcpClient,
}) => {
  // Setup: browser permission to 'ask'
  // ... standard setup ...
  const sidePanel = await openSidePanel(extensionContext);

  const [result] = await Promise.all([
    mcpClient.callTool('browser_open_tab', { url: 'https://example.com' }, { timeout: 35_000 }),
    (async () => {
      await waitForConfirmationDialog(sidePanel);
      const dialog = sidePanel.locator('[role="dialog"]');

      // Parameters summary should be visible
      const summary = dialog.getByText('Parameters');
      await expect(summary).toBeVisible();

      // Click to expand
      await summary.click();

      // Pre should show the JSON params
      const pre = dialog.locator('pre');
      await expect(pre).toBeVisible();
      const text = await pre.textContent();
      expect(text).toContain('https://example.com');

      await sidePanel.getByRole('button', { name: 'Allow' }).click();
    })(),
  ]);

  expect(result.isError).toBe(false);
});

test('dialog does not show Parameters section for tools without params', async ({
  mcpServer, extensionContext, mcpClient,
}) => {
  // ... standard setup ...
  const sidePanel = await openSidePanel(extensionContext);

  const [result] = await Promise.all([
    mcpClient.callTool('browser_list_tabs', {}, { timeout: 35_000 }),
    (async () => {
      await waitForConfirmationDialog(sidePanel);
      const dialog = sidePanel.locator('[role="dialog"]');

      // Parameters section should NOT be present
      await expect(dialog.getByText('Parameters')).toBeHidden({ timeout: 2_000 });

      await sidePanel.getByRole('button', { name: 'Allow' }).click();
    })(),
  ]);

  expect(result.isError).toBe(false);
});
```

Constraints:
- `browser_open_tab` opens a tab — make sure this doesn't break subsequent assertions. The Allow click executes the tool, which opens a new tab. This is fine for the test.

